#!/usr/bin/env python3
"""install_v4.py — ExpeDRY FeatherV2 (v4: NeuKivy shim + RS485 fix + rotation + autoboot)"""
import base64, os, sys
TARGET = sys.argv[1] if len(sys.argv) > 1 else os.path.join(os.path.expanduser('~'), 'FeatherV2')
FILES = {
  "tester.kv": "",
  "setup_service.sh": "",
  "main.py": "",
  "expedry.service": "",
  "camera/values.py": "",
  "camera/__init__.py": "ZnJvbSBjYW1lcmEgaW1wb3J0IHRoZXJtYWxjYW1lcmFDb250cm9sbGVyCmZyb20gY2FtZXJhIGltcG9ydCBndWlDb250cm9sbGVyCmZyb20gY2FtZXJhIGltcG9ydCBDb2xvcm1hcEVudW0KZnJvbSBjYW1lcmEgaW1wb3J0IHZhbHVlcwo=",
  "camera/ColormapEnum.py": "",
  "camera/guiController.py": "",
  "camera/thermalcameraController.py": "",
  "utils/theme.py": "",
  "utils/__init__.py": "ZnJvbSB1dGlscyBpbXBvcnQgdGhlbWUKZnJvbSB1dGlscyBpbXBvcnQgUmVsYXkKZnJvbSB1dGlscyBpbXBvcnQgUlM0ODUKZnJvbSB1dGlscyBpbXBvcnQgU2NhbGUK",
  "utils/Relay.py": "",
  "utils/RS485.py": "",
  "utils/Scale.py": "",
  "components/Controls.py": "",
  "components/WeighDialog.py": "",
  "components/Controls.kv": "",
  "components/WeighDialog.kv": "",
  "components/__init__.py": "",
  "components/WifiDialog.py": "",
  "components/SaveDialog.kv": "",
  "components/WifiDialog.kv": "",
  "components/SaveDialog.py": "",
  "components/Test_Settings.kv": "",
  "components/WarningDialog.py": "",
  "components/WarningDialog.kv": "",
  "components/Test_Settings.py": "",
  "neukivy/__init__.py": "IyBOZXVLaXZ5IGNvbXBhdGliaWxpdHkgc2hpbQojIFJlcGxhY2VzIHRoZSB1bmF2YWlsYWJsZSBHdWhhblNlblNhbS9OZXVLaXZ5IGxpYnJhcnkgd2l0aCBzdGFuZGFyZCBLaXZ5IGVxdWl2YWxlbnRzLgojIFByb3ZpZGVzOiBOZXVBcHAsIE5ldVJvdW5kZWRCdXR0b24sIE5ldUNhcmQg4oCUIHNhbWUgQVBJLCBmbGF0IHN0eWxpbmcuCmZyb20gbmV1a2l2eS5hcHAgaW1wb3J0IE5ldUFwcAo=",
  "neukivy/app.py": "",
  "assets/ExpeDRY_logo.png": "",
  "assets/save-24.png": ""
}
def install():
    print(f"Installing ExpeDRY FeatherV2 to {TARGET}")
    ok = 0
    for rel_path, b64data in FILES.items():
        full_path = os.path.join(TARGET, rel_path)
        d = os.path.dirname(full_path)
        if d: os.makedirs(d, exist_ok=True)
        try:
            with open(full_path, 'wb') as f:
                f.write(base64.b64decode(b64data))
            ok += 1
            print(f"  [{ok}/{len(FILES)}] {rel_path} OK")
        except Exception as e:
            print(f"  [FAIL] {rel_path}: {e}")
    # Make scripts executable
    for s in ['setup_service.sh']:
        p = os.path.join(TARGET, s)
        if os.path.exists(p):
            os.chmod(p, 0o755)
    print(f"\nDone: {ok}/{len(FILES)} files written")
    print(f"\nNext steps:")
    print(f"  1. Launch now:  cd {TARGET} && python3 main.py")
    print(f"  2. Auto-boot:   sudo bash {TARGET}/setup_service.sh")
if __name__ == '__main__':
    install()
